class Solution:
    def divisorGame(self, n):
        # Brute force game DP: win[k] true if mover wins starting from k.
        win = [False] * (n + 1)
        for k in range(2, n + 1):
            can_win = False
            for x in range(1, k):
                if k % x == 0 and not win[k - x]:
                    can_win = True
                    break
            win[k] = can_win
        return win[n]

